      {"type":"category-sort","categories":["Нужна 이","Нужна 가"],"items":[{"text":"물 (вода — согл.)","category":"Нужна 이"},{"text":"비 (дождь — гласн.)","category":"Нужна 가"},{"text":"시간 (время — согл.)","category":"Нужна 이"},{"text":"제 (я вежл. — гласн.)","category":"Нужна 가"},{"text":"바람 (ветер — согл.)","category":"Нужна 이"}]},
