      {"type":"flashcards","cards":[{"front":"을","back":"Объектная частица — после согласной. 밥을 (рис)"},{"front":"를","back":"Объектная частица — после гласной. 커피를 (кофе)"},{"front":"저는 커피를 마셔요","back":"Я пью кофе. (тема + объект + глагол)"},{"front":"한국어를 공부해요","back":"Изучаю корейский язык"}]},
      {"type":"type-answer","question":"Какую частицу добавить к 음악 (музыка, оканч. на согласную)?","acceptedAnswers":["을"]},
      {"type":"drag-order","items":["저는 (я — тема)","커피를 (кофе — объект)","마셔요 (пью — глагол)"]},
      {"type":"category-sort","categories":["Нужна 을","Нужна 를"],"items":[{"text":"밥 (рис — согл.)","category":"Нужна 을"},{"text":"커피 (кофе — гласн.)","category":"Нужна 를"},{"text":"음악 (музыка — согл.)","category":"Нужна 을"},{"text":"영화 (фильм — гласн.)","category":"Нужна 를"},{"text":"책 (книга — согл.)","category":"Нужна 을"},{"text":"우유 (молоко — гласн.)","category":"Нужна 를"}]},
      {"type":"quiz","question":"Каков порядок слов в корейском предложении?","options":[{"id":"a","text":"Подлежащее + Объект + Глагол","correct":True},{"id":"b","text":"Подлежащее + Глагол + Объект","correct":False},{"id":"c","text":"Глагол + Подлежащее + Объект","correct":False},{"id":"d","text":"Объект + Подлежащее + Глагол","correct":False}]},
      {"type":"multi-select","question":"Выберите предложения с правильным использованием 을/를:","options":[{"id":"a","text":"밥을 먹어요","correct":True},{"id":"b","text":"커피를 마셔요","correct":True},{"id":"c","text":"커피을 마셔요","correct":False},{"id":"d","text":"한국어를 공부해요","correct":True}]},
