      {"type":"category-sort","categories":["Желание","Отрицание желания"],"items":[{"text":"가고 싶어요 (хочу идти)","category":"Желание"},{"text":"먹고 싶어요 (хочу есть)","category":"Желание"},{"text":"가고 싶지 않아요 (не хочу идти)","category":"Отрицание желания"},{"text":"먹고 싶지 않아요 (не хочу есть)","category":"Отрицание желания"}]},
      {"type":"quiz","question":"Как спросить «Куда хотите пойти?»","options":[{"id":"a","text":"어디에 가고 싶어요?","correct":True},{"id":"b","text":"어디 가고 싶다?","correct":False},{"id":"c","text":"어디로 싶어요?","correct":False},{"id":"d","text":"가고 어디 싶어요?","correct":False}]},
      {"type":"multi-select","question":"Какие формы с -고 싶다 верны?","options":[{"id":"a","text":"먹고 싶어요","correct":True},{"id":"b","text":"자고 싶어요","correct":True},{"id":"c","text":"보고 싶어요","correct":True},{"id":"d","text":"먹어고 싶어요","correct":False}]},
